    'fr': 'Francia', 'de': 'Alemania', 'it': 'Italia',
    'ja': 'Japón', 'ko': 'Corea del Sur', 'zh': 'China',
    'ar': 'Árabe', 'ru': 'Rusia', 'tr': 'Turquía',
    'nl': 'Países Bajos', 'pl': 'Polonia', 'uk': 'Ucrania'
  };
  return map[(lang||'').toLowerCase()] || null;
}

