  return null;
}
const d = $input.first().json;
const phone   = d.message?.contact?.phone_number || '';
const name    = [d.message?.contact?.first_name, d.message?.contact?.last_name].filter(Boolean).join(' ');
const country = detectCountry(phone);
return [{ json: { ...d, real_phone: phone.replace(/^\+/,''), real_name: name || d.message?.from?.first_name || '', detected_country: country }}];

// Kapso webhook payload — payload version v2
// Structure: { message: { from, text: { body }, kapso: { content } }, conversation: { contact_name, phone_number } }

const body = $input.first().json.body || $input.first().json;

let phone = null;
let messageText = '';
let contactName = '';

// Kapso v2 — real format (message.from + message.text.body)
if (body.message && body.message.from) {
  phone = String(body.message.from).replace('+', '');
  messageText = (body.message.text?.body || body.message.kapso?.content || '').trim();
  contactName = body.conversation?.contact_name || '';
}

// Kapso v2 alt — data.from format
if (!phone && body.data && body.data.from) {
  phone = String(body.data.from).replace('+', '');
  messageText = (body.data.text || body.data.body || '').trim();
}

// Kapso v1
if (!phone && body.from) {
  phone = String(body.from).replace('+', '');
  messageText = (body.text || body.message || '').trim();
}

// Meta webhook format
if (!phone && body.entry) {
  try {
    const changes = body.entry[0].changes[0].value;
    const msg = changes.messages?.[0];
    phone = msg?.from || changes.contacts?.[0]?.wa_id;
    messageText = msg?.text?.body || '';
    contactName = changes.contacts?.[0]?.profile?.name || '';
    if (phone) phone = String(phone).replace('+', '');
  } catch(e) {}
}

if (!phone) {
  throw new Error('No se pudo extraer el telefono del payload: ' + JSON.stringify(body).substring(0, 200));
}

const msgUpper = messageText.toUpperCase();
const isAlta = msgUpper.includes('ALTA') || msgUpper.includes('SUSCRIB') || msgUpper.includes('INSCRIB');
const isStop = msgUpper === 'STOP' || msgUpper.includes('BAJA') || msgUpper.includes('CANCELAR') || msgUpper.includes('DESUSCRIB');

return [{
  json: {
    phone,
    name: contactName,
    message_text: messageText,
    action: isAlta ? 'ALTA' : (isStop ? 'STOP' : 'IGNORE'),
    raw_body: body
  }
}];

